create table dirkspzm32.s_qs_babtec_fauf (
    auftragnr     varchar2(30 char) not null enable,
    artikel       varchar2(30 char),
    kundennr      varchar2(30 char),
    liefermenge   number(*, 3),
    bestellnr     varchar2(30 char),
    benutzer1     varchar2(60 char),
    benutzer2     varchar2(60 char),
    mengeneinheit varchar2(3 char) default 'STK' not null enable,
    status        varchar2(3 char),
    erstell_datum date default sysdate,
    bearb_datum   date,
    fehler_code   number(*, 5),
    fehler_text   varchar2(255 char)
);


